import {
    WorkerMessageType,
    ProcessDeclgenV1Task,
    JobContentType,
    FileInfo,
} from '../types';
import { LogDataFactory, LogData, Logger, getConsoleLogger } from '../logger';
import { ErrorCode, DriverError } from '../util/error';
import { Ets2panda } from '../util/ets2panda';
import { changeFileExtension } from '../util/utils';
import * as path from 'path';
import { ABC_SUFFIX } from '../pre_define';

const logger = Logger.getInstance(getConsoleLogger)

function declgen(id: string, task: ProcessDeclgenV1Task): void {
    const ets2panda = Ets2panda.getInstance(task.buildConfig);

    try {
        ets2panda.initalize();
        if (task.contentType === JobContentType.CLUSTER) {
            for (const fi of (task.content as FileInfo[])) {
                const outPut: string = path.resolve(
                    task.buildConfig.cachePath, task.moduleName,
                    changeFileExtension(
                        path.relative(task.moduleRoot, fi.input),
                        ABC_SUFFIX
                    )
                );
                const subTask: ProcessDeclgenV1Task = {
                    ...task,
                    content: {input: fi.input, output: outPut}
                };
                ets2panda.declgenV1(subTask, subTask.buildConfig.skipDeclCheck ?? true, subTask.buildConfig.genDeclAnnotations ?? true);
            }
        } else {
            ets2panda.declgenV1(task, task.buildConfig.skipDeclCheck ?? true, task.buildConfig.genDeclAnnotations ?? true);
        }

        process.send!({
            type: WorkerMessageType.DECL_GENERATED,
            data: {
                taskId: id,
            }
        });
    } catch (error) {
        if (error instanceof DriverError) {
            process.send!({
                type: WorkerMessageType.ERROR_OCCURED,
                data: {
                    taskId: id,
                    error: error.logData
                }
            });
        }
    } finally {
        ets2panda.finalize();
        process.send!({
            type: WorkerMessageType.TASK_FINISHED,
        });
    }
}

process.on('message', (message: {
    type: WorkerMessageType,
    data: {
        taskId: string,
        payload: ProcessDeclgenV1Task
    }
}) => {
    const { type, data } = message;
    logger.printDebug(`Got message from parent. Type: ${type}`);
    logger.printDebug(`Got message from parent. payload: ${JSON.stringify(data, null, 1)}`);
    try {
        switch (type) {
            case WorkerMessageType.ASSIGN_TASK:
                    declgen(data.taskId, data.payload);
                break;
            default:
                break;
        }
    } catch (error) {
        logger.printDebug('Error occured');
        if (error instanceof Error) {
            let logData: LogData = LogDataFactory.newInstance(
                ErrorCode.BUILDSYSTEM_COMPILE_ABC_FAIL,
                'Compile abc files failed.',
                error.message,
            );
            process.send!({
                type: WorkerMessageType.ERROR_OCCURED,
                data: {
                    taskId: data.taskId,
                    error: logData
                }
            });
        }
        logger.printDebug('Sent the error to the parent');
    }
});

